import { Link } from "react-router-dom";
import StatusDetails from "../../../utils/StatusDetails";
import StatusDrop from "../../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { epochTogmt } from "../../../utils/Common";

export const tableJobDescriptionPositionConstant = (fetchMetaJobDescriptionList, jobDescriptionId) => {
    return [
        {
            id: 1,
            name: "Position Title",
            cell: (row) => {
                return (<span className="sub">{row.position}</span>
                );
            },
            //grid: 3.5,
            sortable: true,
            reorder: true,
            width: "200px",
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Job Id",
            cell: (row) => {
                return (<span className="sub">{row.jobId}</span>
                );
            },
            sortable: true,
            reorder: true,
            width: "150px",
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 3,
            name: "Action",
            //grow: 2.5,
            width: '150px',
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.status}
                        type={'JOB_DESCRIPTION_POSITION'}
                        action={fetchMetaJobDescriptionList}
                        key={uuidv4()}
                        publishPermission={"JOB_DESCRIPTION_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 4,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            //grow: 2.5,
            width: '150px',
            sortable: true,
            reorder: true,
        },
        {
            id: 5,
            name: "Date",
            //grow: 2.5,
            width: '150px',
            selector: (row) => epochTogmt(row.createTime)
        },
        {
            id: 6,
            name: "No of Applicants",
            //grow: 2.5,
            width: '150px',
            cell: (row) => {
                return (row.applicantCount > 0 ?
                    <Link to={`/career/applicant`} state={{ metaJobDescriptionId: row?.id, jobDescriptionId: jobDescriptionId }}>
                        <span className="sub">{row.applicantCount}</span>
                    </Link> : 
                    <span className="sub">{row.applicantCount}</span>
                );
            }
        }
    ];
};
